  1→/**
  2→ * Intent Node Acceptance Test Kit
  3→ *
  4→ * Extends the orchestrator-test-kit with intent-specific helpers.
  5→ * All helpers use business language -- no technical jargon in function names.
  6→ *
  7→ * Driving ports:
  8→ *   POST /api/intents/:id/evaluate  (SurrealQL EVENT target)
  9→ *   POST /api/intents/:id/veto      (human veto)
 10→ *   MCP tools: create_intent, submit_intent, get_intent_status
 11→ */
 12→import { RecordId, type Surreal } from "surrealdb";
 13→
 14→// Re-export everything from orchestrator-test-kit
 15→export {
 16→  setupOrchestratorSuite,
 17→  createTestUser,
 18→  createTestWorkspace,
 19→  createReadyTask,
 20→  createTestProject,
 21→  getTestUserBearerToken,
 22→  fetchJson,
 23→  fetchRaw,
 24→  type OrchestratorTestRuntime,
 25→  type TestUser,
 26→  type TestUserWithToken,
 27→  type TestWorkspace,
 28→  type TestTask,
 29→  type TestProject,
 30→} from "../coding-agent-orchestrator/orchestrator-test-kit";
 31→
 32→import {
 33→  fetchJson,
 34→  type TestUser,
 35→  type TestUserWithToken,
 36→} from "../coding-agent-orchestrator/orchestrator-test-kit";
 37→
 38→// ---------------------------------------------------------------------------
 39→// Intent-Specific Types
 40→// ---------------------------------------------------------------------------
 41→
 42→export type IntentStatus =
 43→  | "draft"
 44→  | "pending_auth"
 45→  | "pending_veto"
 46→  | "authorized"
 47→  | "executing"
 48→  | "completed"
 49→  | "vetoed"
 50→  | "failed";
 51→
 52→export type ActionSpec = {
 53→  provider: string;
 54→  action: string;
 55→  params?: Record<string, unknown>;
 56→};
 57→
 58→export type BudgetLimit = {
 59→  amount: number;
 60→  currency: string;
 61→};
 62→
 63→export type EvaluationResult = {
 64→  decision: "APPROVE" | "REJECT";
 65→  risk_score: number;
 66→  reason: string;
 67→  evaluated_at: string;
 68→  policy_only: boolean;
 69→};
 70→
 71→export type IntentRecord = {
 72→  id: RecordId<"intent">;
 73→  goal: string;
 74→  reasoning: string;
 75→  status: IntentStatus;
 76→  priority: number;
 77→  action_spec: ActionSpec;
 78→  budget_limit?: BudgetLimit;
 79→  evaluation?: EvaluationResult;
 80→  veto_expires_at?: string;
 81→  veto_reason?: string;
 82→  error_reason?: string;
 83→  trace_id: RecordId<"trace">;
 84→  created_at: string;
 85→  updated_at?: string;
 86→};
 87→
 88→export type CreateIntentOptions = {
 89→  goal: string;
 90→  reasoning: string;
 91→  priority?: number;
 92→  action_spec: ActionSpec;
 93→  budget_limit?: BudgetLimit;
 94→  taskId?: string;
 95→};
 96→
 97→// ---------------------------------------------------------------------------
 98→// Domain Helpers -- Business Language Layer
 99→// ---------------------------------------------------------------------------
100→
101→/**
102→ * Creates a draft intent directly in the database.
103→ * Used as a Given-step precondition for scenarios that start
104→ * with an intent already in draft status.
105→ */
106→export async function createDraftIntent(
107→  surreal: Surreal,
108→  workspaceId: string,
109→  requesterId: string,
110→  opts: CreateIntentOptions,
111→): Promise<{ intentId: string; intentRecord: RecordId<"intent"> }> {
112→  const intentId = `intent-${Date.now()}-${Math.floor(Math.random() * 10000)}`;
113→  const intentRecord = new RecordId("intent", intentId);
114→  const workspaceRecord = new RecordId("workspace", workspaceId);
115→  const requesterRecord = new RecordId("identity", requesterId);
116→
117→  // Create trace record for the intent
118→  const traceId = `trace-${intentId}`;
119→  const traceRecord = new RecordId("trace", traceId);
120→  await surreal.query(`CREATE $trace CONTENT $content;`, {
121→    trace: traceRecord,
122→    content: {
123→      type: "intent_submission",
124→      actor: requesterRecord,
125→      workspace: workspaceRecord,
126→      created_at: new Date(),
127→    },
128→  });
129→
130→  const content: Record<string, unknown> = {
131→    goal: opts.goal,
132→    reasoning: opts.reasoning,
133→    status: "draft",
134→    priority: opts.priority ?? 50,
135→    action_spec: opts.action_spec,
136→    trace_id: traceRecord,
137→    requester: requesterRecord,
138→    workspace: workspaceRecord,
139→    created_at: new Date(),
140→  };
141→
142→  if (opts.budget_limit) {
143→    content.budget_limit = opts.budget_limit;
144→  }
145→
146→  await surreal.query(`CREATE $intent CONTENT $content;`, {
147→    intent: intentRecord,
148→    content,
149→  });
150→
151→  // Link to originating task if provided
152→  if (opts.taskId) {
153→    const taskRecord = new RecordId("task", opts.taskId);
154→    await surreal.query(
155→      `RELATE $intent->triggered_by->$task SET created_at = time::now();`,
156→      { intent: intentRecord, task: taskRecord },
157→    );
158→  }
159→
160→  return { intentId, intentRecord };
161→}
162→
163→/**
164→ * Submits a draft intent for authorization.
165→ * Transitions draft -> pending_auth, which triggers the SurrealQL EVENT.
166→ */
167→export async function submitIntent(
168→  surreal: Surreal,
169→  intentId: string,
170→): Promise<void> {
171→  const intentRecord = new RecordId("intent", intentId);
172→  await surreal.query(
173→    `UPDATE $intent SET status = "pending_auth", updated_at = time::now();`,
174→    { intent: intentRecord },
175→  );
176→}
177→
178→/**
179→ * Queries the current status of an intent from the database.
180→ */
181→export async function getIntentStatus(
182→  surreal: Surreal,
183→  intentId: string,
184→): Promise<IntentStatus> {
185→  const intentRecord = new RecordId("intent", intentId);
186→  const rows = (await surreal.query(`SELECT status FROM $intent;`, {
187→    intent: intentRecord,
188→  })) as Array<Array<{ status: IntentStatus }>>;
189→  const result = rows[0]?.[0];
190→  if (!result) {
191→    throw new Error(`Intent ${intentId} not found`);
192→  }
193→  return result.status;
194→}
195→
196→/**
197→ * Queries the full intent record from the database.
198→ */
199→export async function getIntentRecord(
200→  surreal: Surreal,
201→  intentId: string,
202→): Promise<IntentRecord> {
203→  const intentRecord = new RecordId("intent", intentId);
204→  const rows = (await surreal.query(`SELECT * FROM $intent;`, {
205→    intent: intentRecord,
206→  })) as Array<Array<IntentRecord>>;
207→  const result = rows[0]?.[0];
208→  if (!result) {
209→    throw new Error(`Intent ${intentId} not found`);
210→  }
211→  return result;
212→}
213→
214→/**
215→ * Queries the evaluation result for an intent.
216→ */
217→export async function getIntentEvaluation(
218→  surreal: Surreal,
219→  intentId: string,
220→): Promise<EvaluationResult | undefined> {
221→  const record = await getIntentRecord(surreal, intentId);
222→  return record.evaluation;
223→}
224→
225→/**
226→ * Human vetoes an intent within the veto window.
227→ * Exercises the driving port: POST /api/intents/:id/veto
228→ */
229→export async function vetoIntent(
230→  baseUrl: string,
231→  user: TestUser | TestUserWithToken,
232→  workspaceId: string,
233→  intentId: string,
234→  reason: string,
235→): Promise<{ vetoed: boolean }> {
236→  return fetchJson<{ vetoed: boolean }>(
237→    `${baseUrl}/api/workspaces/${workspaceId}/intents/${intentId}/veto`,
238→    {
239→      method: "POST",
240→      headers: { "Content-Type": "application/json", ...user.headers },
241→      body: JSON.stringify({ reason }),
242→    },
243→  );
244→}
245→
246→/**
247→ * Lists intents in the governance feed that are pending human review.
248→ */
249→export async function listPendingIntents(
250→  surreal: Surreal,
251→  workspaceId: string,
252→): Promise<IntentRecord[]> {
253→  const workspaceRecord = new RecordId("workspace", workspaceId);
254→  const rows = (await surreal.query(
255→    `SELECT * FROM intent
256→     WHERE workspace = $ws AND status IN ["pending_veto"]
257→     ORDER BY priority DESC, created_at ASC;`,
258→    { ws: workspaceRecord },
259→  )) as Array<IntentRecord[]>;
260→  return rows[0] ?? [];
261→}
262→
263→/**
264→ * Creates an intent via the MCP tool endpoint (driving port).
265→ */
266→export async function createIntentViaMcp(
267→  baseUrl: string,
268→  user: TestUserWithToken,
269→  workspaceId: string,
270→  opts: CreateIntentOptions,
271→): Promise<{ intentId: string }> {
272→  const res = await user.mcpFetch(
273→    `/api/mcp/${workspaceId}/tools/create_intent`,
274→    {
275→      body: {
276→        goal: opts.goal,
277→        reasoning: opts.reasoning,
278→        priority: opts.priority ?? 50,
279→        action_spec: opts.action_spec,
280→        budget_limit: opts.budget_limit,
281→        task_id: opts.taskId,
282→      },
283→    },
284→  );
285→  if (!res.ok) throw new Error(`createIntentViaMcp failed: ${res.status} ${await res.text()}`);
286→  return res.json() as Promise<{ intentId: string }>;
287→}
288→
289→/**
290→ * Submits an intent via the MCP tool endpoint (driving port).
291→ */
292→export async function submitIntentViaMcp(
293→  baseUrl: string,
294→  user: TestUserWithToken,
295→  workspaceId: string,
296→  intentId: string,
297→): Promise<{ status: IntentStatus }> {
298→  const res = await user.mcpFetch(
299→    `/api/mcp/${workspaceId}/tools/submit_intent`,
300→    { body: { intent_id: intentId } },
301→  );
302→  if (!res.ok) throw new Error(`submitIntentViaMcp failed: ${res.status} ${await res.text()}`);
303→  return res.json() as Promise<{ status: IntentStatus }>;
304→}
305→
306→/**
307→ * Gets intent status via the MCP tool endpoint (driving port).
308→ */
309→export async function getIntentStatusViaMcp(
310→  baseUrl: string,
311→  user: TestUserWithToken,
312→  workspaceId: string,
313→  intentId: string,
314→): Promise<{ intentId: string; status: IntentStatus }> {
315→  const res = await user.mcpFetch(
316→    `/api/mcp/${workspaceId}/tools/get_intent_status`,
317→    { body: { intent_id: intentId } },
318→  );
319→  if (!res.ok) throw new Error(`getIntentStatusViaMcp failed: ${res.status} ${await res.text()}`);
320→  return res.json() as Promise<{ intentId: string; status: IntentStatus }>;
321→}
322→
323→/**
324→ * Polls until an intent reaches the target status or times out.
325→ * Used to wait for async evaluation pipeline (SurrealQL EVENT -> evaluate -> status update).
326→ */
327→export async function waitForIntentStatus(
328→  surreal: Surreal,
329→  intentId: string,
330→  targetStatus: IntentStatus | IntentStatus[],
331→  timeoutMs = 30_000,
332→): Promise<IntentStatus> {
333→  const targets = Array.isArray(targetStatus) ? targetStatus : [targetStatus];
334→  const start = Date.now();
335→
336→  while (Date.now() - start < timeoutMs) {
337→    const current = await getIntentStatus(surreal, intentId);
338→    if (targets.includes(current)) {
339→      return current;
340→    }
341→    await Bun.sleep(250);
342→  }
343→
344→  const finalStatus = await getIntentStatus(surreal, intentId);
345→  throw new Error(
346→    `Intent ${intentId} did not reach ${targets.join("|")} within ${timeoutMs}ms. ` +
347→    `Current status: ${finalStatus}`,
348→  );
349→}
350→
351→/**
352→ * Simulates the evaluation endpoint completing (for tests where the
353→ * SurrealQL EVENT may not fire in the test environment).
354→ * Directly updates the intent with an evaluation result and new status.
355→ */
356→export async function simulateEvaluation(
357→  surreal: Surreal,
358→  intentId: string,
359→  evaluation: {
360→    decision: "APPROVE" | "REJECT";
361→    risk_score: number;
362→    reason: string;
363→    policy_only?: boolean;
364→  },
365→  resultStatus: IntentStatus,
366→): Promise<void> {
367→  const intentRecord = new RecordId("intent", intentId);
368→  const evalContent = {
369→    decision: evaluation.decision,
370→    risk_score: evaluation.risk_score,
371→    reason: evaluation.reason,
372→    evaluated_at: new Date(),
373→    policy_only: evaluation.policy_only ?? false,
374→  };
375→
376→  const updates: Record<string, unknown> = {
377→    status: resultStatus,
378→    evaluation: evalContent,
379→    updated_at: new Date(),
380→  };
381→
382→  // If entering veto window, set expiry
383→  if (resultStatus === "pending_veto") {
384→    const expiresAt = new Date(Date.now() + 5 * 60 * 1000); // 5 min default
385→    updates.veto_expires_at = expiresAt;
386→  }
387→
388→  await surreal.query(`UPDATE $intent MERGE $updates;`, {
389→    intent: intentRecord,
390→    updates,
391→  });
392→}
393→
394→/**
395→ * Queries the identity record for a user to get the identity ID.
396→ * Needed because intent.requester links to identity, not user.
397→ */
398→export async function getIdentityId(
399→  surreal: Surreal,
400→): Promise<string> {
401→  const rows = (await surreal.query(
402→    `SELECT id FROM identity LIMIT 1;`,
403→  )) as Array<Array<{ id: RecordId<"identity"> }>>;
404→  const result = rows[0]?.[0];
405→  if (!result) {
