225→export async function simulatePolicyGateResult(
226→  surreal: Surreal,
227→  intentId: string,
228→  result: {
229→    decision: "APPROVE" | "REJECT";
230→    risk_score: number;
231→    reason: string;
232→    policy_only: boolean;
233→    policy_trace: PolicyTraceEntry[];
234→    human_veto_required?: boolean;
235→  },
236→  resultStatus: "authorized" | "pending_veto" | "vetoed",
237→): Promise<void> {
238→  const intentRecord = new RecordId("intent", intentId);
239→  const evalContent: Record<string, unknown> = {
240→    decision: result.decision,
241→    risk_score: result.risk_score,
242→    reason: result.reason,
243→    evaluated_at: new Date(),
244→    policy_only: result.policy_only,
245→    policy_trace: result.policy_trace,
246→  };
247→  if (result.human_veto_required !== undefined) {
248→    evalContent.human_veto_required = result.human_veto_required;
249→  }
250→
251→  const updates: Record<string, unknown> = {
252→    status: resultStatus,
253→    evaluation: evalContent,
254→    updated_at: new Date(),
255→  };
256→
257→  if (resultStatus === "pending_veto") {
258→    updates.veto_expires_at = new Date(Date.now() + 5 * 60 * 1000);
259→  }
260→
261→  await surreal.query(`UPDATE $intent MERGE $updates;`, {
262→    intent: intentRecord,
263→    updates,
264→  });
265→}
