 40→describe("Walking Skeleton: Policy deny rule blocks intent before LLM tier", () => {
 41→  // ---------------------------------------------------------------------------
 42→  // Skeleton 1: Active deny policy rejects intent deterministically
 43→  // US-4 + US-5 + US-7 happy path
 44→  // ---------------------------------------------------------------------------
 45→  it("active deny policy blocks a deploy intent and records policy trace", async () => {
 46→    const { baseUrl, surreal } = getRuntime();
 47→
 48→    // Given a workspace with a human admin who creates governance policies
 49→    const user = await createTestUser(baseUrl, "skel-deny");
 50→    const workspace = await createTestWorkspace(baseUrl, user);
 51→    const adminId = await createTestIdentity(surreal, "admin-1", "human", workspace.workspaceId);
 52→
 53→    // And an active policy that denies deploy actions
 54→    const { policyId } = await createPolicy(surreal, workspace.workspaceId, adminId, {
 55→      title: "Block Production Deploys",
 56→      rules: [{
 57→        id: "no_deploy",
 58→        condition: { field: "action_spec.action", operator: "eq", value: "deploy" },
 59→        effect: "deny",
 60→        priority: 100,
 61→      }],
 62→    });
 63→    await activatePolicy(surreal, policyId, adminId, workspace.workspaceId);
 64→
 65→    // And an agent identity that submits an intent to deploy
 66→    const agentId = await createTestIdentity(surreal, "coding-agent", "agent", workspace.workspaceId);
 67→
 68→    const { intentId } = await createDraftIntent(
 69→      surreal,
 70→      workspace.workspaceId,
 71→      agentId,
 72→      {
 73→        goal: "Deploy latest build to production",
 74→        reasoning: "CI passed, ready for release",
 75→        action_spec: { provider: "infra", action: "deploy", params: { env: "production" } },
 76→      },
 77→    );
 78→
 79→    // When the agent submits the intent and the policy gate evaluates it
 80→    await submitIntent(surreal, intentId);
 81→
 82→    // Then the policy gate loads the active policy via graph traversal
 83→    const policies = await loadActivePoliciesForIdentity(surreal, adminId, workspace.workspaceId);
 84→    expect(policies.length).toBeGreaterThanOrEqual(1);
 85→    const blockPolicy = policies.find(p => (p.id.id as string) === policyId);
 86→    expect(blockPolicy).toBeDefined();
 87→    expect(blockPolicy!.status).toBe("active");
 88→
 89→    // And the deny rule matches, so the intent is rejected before LLM evaluation
 90→    await simulatePolicyGateResult(surreal, intentId, {
 91→      decision: "REJECT",
 92→      risk_score: 0,
 93→      reason: "Policy deny rule 'no_deploy' matched: action_spec.action == deploy",
 94→      policy_only: true,
 95→      policy_trace: [{
 96→        policy_id: policyId,
 97→        policy_version: 1,
 98→        rule_id: "no_deploy",
 99→        effect: "deny",
100→        matched: true,
101→        priority: 100,
102→      }],
103→    }, "vetoed");
104→
105→    // Then the intent is rejected
106→    const status = await getIntentStatus(surreal, intentId);
107→    expect(status).toBe("vetoed");
108→
109→    // And the evaluation shows it was policy-only (no LLM call)
110→    const evaluation = await getIntentEvaluation(surreal, intentId);
111→    expect(evaluation).toBeDefined();
112→    expect(evaluation!.policy_only).toBe(true);
113→    expect(evaluation!.decision).toBe("REJECT");
114→
115→    // And the policy trace is recorded on the intent
116→    const record = await getIntentRecord(surreal, intentId);
117→    const trace = (record.evaluation as Record<string, unknown>)?.policy_trace as PolicyTraceEntry[];
118→    expect(trace).toBeDefined();
119→    expect(trace).toHaveLength(1);
120→    expect(trace[0].rule_id).toBe("no_deploy");
121→    expect(trace[0].matched).toBe(true);
122→    expect(trace[0].effect).toBe("deny");
123→  }, 120_000);
124→});
