101→/**
102→ * Creates a draft intent directly in the database.
103→ * Used as a Given-step precondition for scenarios that start
104→ * with an intent already in draft status.
105→ */
106→export async function createDraftIntent(
107→  surreal: Surreal,
108→  workspaceId: string,
109→  requesterId: string,
110→  opts: CreateIntentOptions,
111→): Promise<{ intentId: string; intentRecord: RecordId<"intent"> }> {
112→  const intentId = `intent-${Date.now()}-${Math.floor(Math.random() * 10000)}`;
113→  const intentRecord = new RecordId("intent", intentId);
114→  const workspaceRecord = new RecordId("workspace", workspaceId);
115→  const requesterRecord = new RecordId("identity", requesterId);
116→
117→  // Create trace record for the intent
118→  const traceId = `trace-${intentId}`;
119→  const traceRecord = new RecordId("trace", traceId);
120→  await surreal.query(`CREATE $trace CONTENT $content;`, {
121→    trace: traceRecord,
122→    content: {
123→      type: "intent_submission",
124→      actor: requesterRecord,
125→      workspace: workspaceRecord,
126→      created_at: new Date(),
127→    },
128→  });
129→
130→  const content: Record<string, unknown> = {
131→    goal: opts.goal,
132→    reasoning: opts.reasoning,
133→    status: "draft",
134→    priority: opts.priority ?? 50,
135→    action_spec: opts.action_spec,
136→    trace_id: traceRecord,
137→    requester: requesterRecord,
138→    workspace: workspaceRecord,
139→    created_at: new Date(),
140→  };
141→
142→  if (opts.budget_limit) {
143→    content.budget_limit = opts.budget_limit;
144→  }
145→
146→  await surreal.query(`CREATE $intent CONTENT $content;`, {
147→    intent: intentRecord,
148→    content,
149→  });
150→
151→  // Link to originating task if provided
152→  if (opts.taskId) {
153→    const taskRecord = new RecordId("task", opts.taskId);
154→    await surreal.query(
155→      `RELATE $intent->triggered_by->$task SET created_at = time::now();`,
156→      { intent: intentRecord, task: taskRecord },
157→    );
158→  }
159→
160→  return { intentId, intentRecord };
161→}
