351→/**
352→ * Simulates the evaluation endpoint completing (for tests where the
353→ * SurrealQL EVENT may not fire in the test environment).
354→ * Directly updates the intent with an evaluation result and new status.
355→ */
356→export async function simulateEvaluation(
357→  surreal: Surreal,
358→  intentId: string,
359→  evaluation: {
360→    decision: "APPROVE" | "REJECT";
361→    risk_score: number;
362→    reason: string;
363→    policy_only?: boolean;
364→  },
365→  resultStatus: IntentStatus,
366→): Promise<void> {
367→  const intentRecord = new RecordId("intent", intentId);
368→  const evalContent = {
369→    decision: evaluation.decision,
370→    risk_score: evaluation.risk_score,
371→    reason: evaluation.reason,
372→    evaluated_at: new Date(),
373→    policy_only: evaluation.policy_only ?? false,
374→  };
375→
376→  const updates: Record<string, unknown> = {
377→    status: resultStatus,
378→    evaluation: evalContent,
379→    updated_at: new Date(),
380→  };
381→
382→  // If entering veto window, set expiry
383→  if (resultStatus === "pending_veto") {
384→    const expiresAt = new Date(Date.now() + 5 * 60 * 1000); // 5 min default
385→    updates.veto_expires_at = expiresAt;
386→  }
387→
388→  await surreal.query(`UPDATE $intent MERGE $updates;`, {
389→    intent: intentRecord,
390→    updates,
391→  });
392→}
